#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
class Solution { public:
bool solve(vector<vector<int>>& grid) { for (int i = 0; i < 9; i++) { for (int j = 0; j < 9; j++) { if (grid[i][j] == 0) { for (int k = 1; k <= 9; k++) { if (isValid(grid, i, j, k)) { grid[i][j] = k; if (solve(grid)) return true; } } grid[i][j] = 0; return false; } } } return true; }
bool isValid(vector<vector<int>>& grid, int row, int col, int num) {
for (int i = 0; i < 9; i++) {
if (grid[row][i] == num || grid[i][col] == num) return false;
}
for (int i = 0; i < 3; i++) {
for (int j = 0; j < 3; j++) {
if (grid[3 * (row / 3) + i][3 * (col / 3) + j] == num) return false;
}
}
return true;
}
};
class Reader { public:
static int readInt() { int x; cin >> x; return x; }
};
class Writer { public:
static void printInt(int x) { cout << x << endl; }
};
class Main {
public:
static int main() {
int t = Reader::readInt();
for (; t > 0; --t) {
vector<vector<int>> grid(9, vector<int>(9));
for (int i = 0; i < 9; i++) {
for (int j = 0; j < 9; j++) {
grid[i][j] = Reader::readInt();
}
}
Solution sol;
Writer::printInt(sol.solve(grid) ? 1 : 0);
}
return 0;
}
};

int main() {
return Main::main();
}
